// Simpler O(n) approach
double findMedian(int[] a, int[] b){
  int[] merged = new int[a.length + b.length];
  int i=0,j=0,k=0;
  while(i<a.length && j<b.length) merged[k++] = a[i]<=b[j] ? a[i++] : b[j++];
  while(i<a.length) merged[k++]=a[i++];
  while(j<b.length) merged[k++]=b[j++];
  int n = merged.length;
  return n % 2 == 0 ? (merged[n/2-1]+merged[n/2])/2.0 : merged[n/2];
}

List<Integer> topKFrequent(int[] arr, int k){
  Map<Integer,Integer> freq = new HashMap<>();
  for(int x : arr) freq.put(x, freq.getOrDefault(x,0)+1);
  return freq.entrySet().stream()
    .sorted((a,b) -> b.getValue() - a.getValue())
    .limit(k)
    .map(Map.Entry::getKey)
    .collect(Collectors.toList());
}

void permute(char[] arr, int idx, List<String> result){
  if(idx == arr.length){ result.add(new String(arr)); return; }
  for(int i = idx; i < arr.length; i++){
    char t=arr[idx]; arr[idx]=arr[i]; arr[i]=t;
    permute(arr, idx+1, result);
    t=arr[idx]; arr[idx]=arr[i]; arr[i]=t;
  }
}

boolean isPalindromeNumber(int n){
  if(n < 0) return false;
  int original = n, reversed = 0;
  while(n > 0){
    reversed = reversed * 10 + n % 10;
    n /= 10;
  }
  return reversed == original;
}

Node getIntersection(Node a, Node b, int lenA, int lenB){
  while(lenA > lenB){ a = a.next; lenA--; }
  while(lenB > lenA){ b = b.next; lenB--; }
  while(a != b){ a = a.next; b = b.next; }
  return a;
}

class TrieNode {
  Map<Character, TrieNode> children = new HashMap<>();
  boolean isEnd = false;
}
class Trie {
  TrieNode root = new TrieNode();
  void insert(String word){
    TrieNode node = root;
    for(char c : word.toCharArray())
      node = node.children.computeIfAbsent(c, k -> new TrieNode());
    node.isEnd = true;
  }
}

List<Integer> spiralOrder(int[][] m){
  List<Integer> result = new ArrayList<>();
  int top=0, bottom=m.length-1, left=0, right=m[0].length-1;
  while(top<=bottom && left<=right){
    for(int j=left;j<=right;j++) result.add(m[top][j]);
    top++;
    for(int i=top;i<=bottom;i++) result.add(m[i][right]);
    right--;
    if(top<=bottom){ for(int j=right;j>=left;j--) result.add(m[bottom][j]); bottom--; }
    if(left<=right){ for(int i=bottom;i>=top;i--) result.add(m[i][left]); left++; }
  }
  return result;
}

