int lengthOfLIS(int[] arr){
  int[] dp = new int[arr.length];
  Arrays.fill(dp, 1);
  int max = 1;
  for(int i = 1; i < arr.length; i++){
    for(int j = 0; j < i; j++){
      if(arr[j] < arr[i]) dp[i] = Math.max(dp[i], dp[j]+1);
    }
    max = Math.max(max, dp[i]);
  }
  return max;
}

