int mostFrequent(int[] arr){
  Map<Integer,Integer> freq = new HashMap<>();
  for(int x : arr) freq.put(x, freq.getOrDefault(x,0)+1);
  int maxCount=0, result=arr[0];
  for(Map.Entry<Integer,Integer> e : freq.entrySet()){
    if(e.getValue() > maxCount){ maxCount = e.getValue(); result = e.getKey(); }
  }
  return result;
}

void insertAt(Node head, int position, int data){
  Node newNode = new Node(data);
  if(position == 0){ newNode.next = head; return; }
  Node current = head;
  for(int i=0;i<position-1 && current!=null;i++) current = current.next;
  newNode.next = current.next;
  current.next = newNode;
}
